from openai import OpenAI

client = OpenAI()

JUDGE_TEMPLATE = """You are an expert evaluator. Compare these two responses and pick the better one.

Prompt: {prompt}

Response A:
{response_a}

Response B:
{response_b}

Which response is better? Answer with just the letter A or B."""

def get_ai_preference(prompt: str, response_a: str, response_b: str) -> str:
    """Returns 'A' or 'B'. Uses temperature=0 for determinism."""
    content = JUDGE_TEMPLATE.format(
        prompt=prompt, response_a=response_a, response_b=response_b
    )
    result = client.chat.completions.create(
        model="gpt-4o",
        messages=[{"role": "user", "content": content}],
        max_tokens=1,
        temperature=0,
    )
    return result.choices[0].message.content.strip().upper()

import torch

def get_soft_preference(
    judge_logprobs: dict,    # {'A': log_prob_A, 'B': log_prob_B}
) -> float:
    """
    Returns soft preference probability for A over B in [0, 1].
    Extracted from the judge's logprobs at the first answer token.
    """
    log_p_A = judge_logprobs.get('A', -100.0)
    log_p_B = judge_logprobs.get('B', -100.0)
    # Numerically stable softmax of two values
    lse = torch.logsumexp(torch.tensor([log_p_A, log_p_B]), dim=0).item()
    return (log_p_A - lse)  # log P(A) - log(P(A)+P(B))

def weighted_dpo_loss(
    chosen_rewards: torch.Tensor,     # shape (batch,)
    rejected_rewards: torch.Tensor,
    soft_weights: torch.Tensor,       # shape (batch,), in [0.5, 1]
) -> torch.Tensor:
    import torch.nn.functional as F
    logits = chosen_rewards - rejected_rewards
    per_example_loss = -F.logsigmoid(logits)
    return (per_example_loss * soft_weights).mean()
